/**
 * Notification log model — tracks the history of all sent notifications.
 *
 * Every notification that passes through NotificationService is logged here,
 * capturing recipient, channel, type, delivery status, and timestamp.
 */

import type { NotificationChannel, NotificationType, NotificationStatus } from './notification.js';

/**
 * A persisted notification log entry.
 */
export interface NotificationLogEntry {
  id: string;
  /** The original notification ID from NotificationService */
  notificationId: string;
  /** Who received the notification */
  recipient: string;
  /** Delivery channel used */
  channel: NotificationChannel;
  /** Notification category */
  type: NotificationType;
  /** Delivery status at time of logging */
  status: NotificationStatus;
  /** Subject line of the notification */
  subject: string;
  /** Body content of the notification */
  body: string;
  /** Optional error message if delivery failed */
  error?: string;
  /** When the notification was sent/attempted */
  sentAt: Date;
  /** When this log entry was created */
  loggedAt: Date;
}

/**
 * Query filter for searching notification history.
 */
export interface NotificationHistoryQuery {
  /** Filter by recipient */
  recipient?: string;
  /** Filter by notification type */
  type?: NotificationType;
  /** Filter by delivery channel */
  channel?: NotificationChannel;
  /** Filter by delivery status */
  status?: NotificationStatus;
  /** Filter entries on or after this date */
  from?: Date;
  /** Filter entries on or before this date */
  to?: Date;
}

/**
 * Repository for notification log entries.
 *
 * Extends BaseRepository with query methods for searching
 * notification history by recipient, type, channel, and date range.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLogEntry } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType, NotificationStatus } from '../models/notification.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLogEntry> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLogEntry {
    const entry: NotificationLogEntry = {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      status: record['status'] as NotificationStatus,
      subject: record['subject'] as string,
      body: record['body'] as string,
      sentAt: new Date(record['sentAt'] as string),
      loggedAt: new Date(record['loggedAt'] as string),
    };
    if (record['error']) {
      entry.error = record['error'] as string;
    }
    return entry;
  }

  protected toRecord(entity: NotificationLogEntry): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      status: entity.status,
      subject: entity.subject,
      body: entity.body,
      sentAt: entity.sentAt.toISOString(),
      loggedAt: entity.loggedAt.toISOString(),
    };
    if (entity.error) {
      record['error'] = entity.error;
    }
    return record;
  }

  findByRecipient(recipient: string): NotificationLogEntry[] {
    return this.findAll((entry) => entry.recipient === recipient);
  }

  findByType(type: NotificationType): NotificationLogEntry[] {
    return this.findAll((entry) => entry.type === type);
  }

  findByChannel(channel: NotificationChannel): NotificationLogEntry[] {
    return this.findAll((entry) => entry.channel === channel);
  }

  findByStatus(status: NotificationStatus): NotificationLogEntry[] {
    return this.findAll((entry) => entry.status === status);
  }

  findByDateRange(from: Date, to: Date): NotificationLogEntry[] {
    return this.findAll((entry) => entry.sentAt >= from && entry.sentAt <= to);
  }
}

/**
 * Notification history service — logs and queries notification history.
 *
 * Integrates with the notification flow by listening to notification:sent
 * and notification:failed events on the EventBus. Every notification that
 * passes through NotificationService is automatically logged.
 *
 * Depends on:
 * - EventBus for receiving notification events
 * - NotificationLogRepository for persistence
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationSentEvent, NotificationFailedEvent } from '../events/event-types.js';
import type { NotificationLogEntry, NotificationHistoryQuery } from '../models/notification-log.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateLogId(): string {
  return `nlog-${String(nextId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(
    private repository: NotificationLogRepository,
    private eventBus: EventBus,
  ) {
    this.registerEventHandlers();
  }

  /**
   * Log a successful notification delivery.
   */
  logSent(event: NotificationSentEvent): NotificationLogEntry {
    const entry: NotificationLogEntry = {
      id: generateLogId(),
      notificationId: event.notification.id,
      recipient: event.notification.recipient,
      channel: event.notification.channel,
      type: event.notification.type,
      status: event.notification.status,
      subject: event.notification.subject,
      body: event.notification.body,
      sentAt: event.notification.sentAt,
      loggedAt: new Date(),
    };

    this.repository.save(entry);
    this.logger.info(`Logged sent notification: ${entry.notificationId}`);
    return entry;
  }

  /**
   * Log a failed notification delivery.
   */
  logFailed(event: NotificationFailedEvent): NotificationLogEntry {
    const entry: NotificationLogEntry = {
      id: generateLogId(),
      notificationId: 'unknown',
      recipient: event.recipient,
      channel: event.channel as NotificationLogEntry['channel'],
      type: 'system-alert',
      status: 'failed',
      subject: '',
      body: '',
      error: event.error,
      sentAt: event.timestamp,
      loggedAt: new Date(),
    };

    this.repository.save(entry);
    this.logger.info(`Logged failed notification for ${event.recipient}: ${event.error}`);
    return entry;
  }

  /**
   * Query notification history with flexible filters.
   */
  query(filters: NotificationHistoryQuery): NotificationLogEntry[] {
    return this.repository.findAll((entry) => {
      if (filters.recipient && entry.recipient !== filters.recipient) return false;
      if (filters.type && entry.type !== filters.type) return false;
      if (filters.channel && entry.channel !== filters.channel) return false;
      if (filters.status && entry.status !== filters.status) return false;
      if (filters.from && entry.sentAt < filters.from) return false;
      if (filters.to && entry.sentAt > filters.to) return false;
      return true;
    });
  }

  /**
   * Get all log entries for a specific recipient.
   */
  getByRecipient(recipient: string): NotificationLogEntry[] {
    return this.repository.findByRecipient(recipient);
  }

  /**
   * Get all log entries.
   */
  getAll(): NotificationLogEntry[] {
    return this.repository.findAll();
  }

  /**
   * Get the total count of log entries.
   */
  count(): number {
    return this.repository.count();
  }

  private registerEventHandlers(): void {
    this.eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
      this.logSent(event);
    });

    this.eventBus.on<NotificationFailedEvent>('notification:failed', (event) => {
      this.logFailed(event);
    });
  }
}

