import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { Database } from '../../src/utils/database.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { NotificationSentEvent, NotificationFailedEvent } from '../../src/events/event-types.js';
import type { Notification } from '../../src/models/notification.js';

function makeNotification(overrides: Partial<Notification> = {}): Notification {
  return {
    id: 'notif-0001',
    recipient: 'alice@example.com',
    type: 'order-confirmation',
    channel: 'email',
    subject: 'Order Confirmation',
    body: 'Your order has been placed.',
    status: 'sent',
    sentAt: new Date('2026-01-15T10:00:00Z'),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let eventBus: EventBus;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository, eventBus);
    resetLogIdCounter();
    resetNotificationIdCounter();
  });

  describe('logSent', () => {
    it('should log a sent notification', () => {
      const event: NotificationSentEvent = {
        type: 'notification:sent',
        notification: makeNotification(),
        timestamp: new Date(),
      };

      const entry = historyService.logSent(event);

      expect(entry.id).toBe('nlog-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order-confirmation');
      expect(entry.status).toBe('sent');
      expect(entry.subject).toBe('Order Confirmation');
      expect(entry.body).toBe('Your order has been placed.');
      expect(entry.loggedAt).toBeInstanceOf(Date);
    });

    it('should persist the entry to the repository', () => {
      const event: NotificationSentEvent = {
        type: 'notification:sent',
        notification: makeNotification(),
        timestamp: new Date(),
      };

      historyService.logSent(event);

      expect(repository.count()).toBe(1);
      const saved = repository.findById('nlog-0001');
      expect(saved).toBeDefined();
      expect(saved!.recipient).toBe('alice@example.com');
    });
  });

  describe('logFailed', () => {
    it('should log a failed notification', () => {
      const event: NotificationFailedEvent = {
        type: 'notification:failed',
        recipient: 'bob@example.com',
        channel: 'sms',
        error: 'No adapter registered for channel: sms',
        timestamp: new Date('2026-01-15T10:00:00Z'),
      };

      const entry = historyService.logFailed(event);

      expect(entry.id).toBe('nlog-0001');
      expect(entry.recipient).toBe('bob@example.com');
      expect(entry.channel).toBe('sms');
      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('No adapter registered for channel: sms');
    });
  });

  describe('event-driven logging', () => {
    it('should automatically log when notification:sent is emitted', async () => {
      const event: NotificationSentEvent = {
        type: 'notification:sent',
        notification: makeNotification(),
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.count()).toBe(1);
      const entries = historyService.getAll();
      expect(entries[0]!.notificationId).toBe('notif-0001');
    });

    it('should automatically log when notification:failed is emitted', async () => {
      const event: NotificationFailedEvent = {
        type: 'notification:failed',
        recipient: 'bob@example.com',
        channel: 'email',
        error: 'SMTP timeout',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.count()).toBe(1);
      const entries = historyService.getAll();
      expect(entries[0]!.status).toBe('failed');
      expect(entries[0]!.error).toBe('SMTP timeout');
    });

    it('should log notifications sent through NotificationService.send()', async () => {
      const notificationService = new NotificationService(eventBus);
      notificationService.registerAdapter({
        channel: 'email',
        async send() {
          return { success: true };
        },
      });

      await notificationService.send({
        recipient: 'alice@example.com',
        type: 'system-alert',
        channel: 'email',
        subject: 'Alert',
        body: 'Something happened.',
      });

      expect(historyService.count()).toBe(1);
      const entries = historyService.getAll();
      expect(entries[0]!.recipient).toBe('alice@example.com');
      expect(entries[0]!.status).toBe('sent');
    });

    it('should log failed notifications from NotificationService', async () => {
      const notificationService = new NotificationService(eventBus);

      await notificationService.send({
        recipient: 'alice@example.com',
        type: 'system-alert',
        channel: 'sms',
        subject: 'Alert',
        body: 'No adapter.',
      });

      expect(historyService.count()).toBe(1);
      const entries = historyService.getAll();
      expect(entries[0]!.status).toBe('failed');
    });
  });

  describe('query', () => {
    beforeEach(async () => {
      // Populate with several log entries
      historyService.logSent({
        type: 'notification:sent',
        notification: makeNotification({
          id: 'notif-0001',
          recipient: 'alice@example.com',
          type: 'order-confirmation',
          channel: 'email',
          sentAt: new Date('2026-01-10T10:00:00Z'),
        }),
        timestamp: new Date(),
      });
      historyService.logSent({
        type: 'notification:sent',
        notification: makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          type: 'order-status-update',
          channel: 'email',
          sentAt: new Date('2026-01-15T10:00:00Z'),
        }),
        timestamp: new Date(),
      });
      historyService.logSent({
        type: 'notification:sent',
        notification: makeNotification({
          id: 'notif-0003',
          recipient: 'alice@example.com',
          type: 'system-alert',
          channel: 'webhook',
          sentAt: new Date('2026-01-20T10:00:00Z'),
        }),
        timestamp: new Date(),
      });
      historyService.logFailed({
        type: 'notification:failed',
        recipient: 'charlie@example.com',
        channel: 'sms',
        error: 'No adapter',
        timestamp: new Date('2026-01-25T10:00:00Z'),
      });
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      expect(results.every((e) => e.recipient === 'alice@example.com')).toBe(true);
    });

    it('should filter by type', () => {
      const results = historyService.query({ type: 'order-confirmation' });
      expect(results).toHaveLength(1);
      expect(results[0]!.type).toBe('order-confirmation');
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]!.channel).toBe('webhook');
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]!.recipient).toBe('charlie@example.com');
    });

    it('should filter by date range', () => {
      const results = historyService.query({
        from: new Date('2026-01-12T00:00:00Z'),
        to: new Date('2026-01-22T00:00:00Z'),
      });
      expect(results).toHaveLength(2);
    });

    it('should combine multiple filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        channel: 'email',
      });
      expect(results).toHaveLength(1);
      expect(results[0]!.type).toBe('order-confirmation');
    });

    it('should return all entries when no filters provided', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(4);
    });

    it('should return empty array when no entries match', () => {
      const results = historyService.query({ recipient: 'nobody@example.com' });
      expect(results).toHaveLength(0);
    });
  });

  describe('getByRecipient', () => {
    it('should return entries for a specific recipient', () => {
      historyService.logSent({
        type: 'notification:sent',
        notification: makeNotification({ recipient: 'alice@example.com' }),
        timestamp: new Date(),
      });
      historyService.logSent({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0002', recipient: 'bob@example.com' }),
        timestamp: new Date(),
      });

      const results = historyService.getByRecipient('alice@example.com');
      expect(results).toHaveLength(1);
      expect(results[0]!.recipient).toBe('alice@example.com');
    });
  });

  describe('getAll and count', () => {
    it('should return all entries', () => {
      expect(historyService.getAll()).toHaveLength(0);
      expect(historyService.count()).toBe(0);

      historyService.logSent({
        type: 'notification:sent',
        notification: makeNotification(),
        timestamp: new Date(),
      });

      expect(historyService.getAll()).toHaveLength(1);
      expect(historyService.count()).toBe(1);
    });

    it('should generate sequential log IDs', () => {
      historyService.logSent({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0001' }),
        timestamp: new Date(),
      });
      historyService.logSent({
        type: 'notification:sent',
        notification: makeNotification({ id: 'notif-0002' }),
        timestamp: new Date(),
      });

      const entries = historyService.getAll();
      expect(entries[0]!.id).toBe('nlog-0001');
      expect(entries[1]!.id).toBe('nlog-0002');
    });
  });
});
